-- Gold layer: analytics-ready feature tables.
-- Parameterize {{catalog}}. These CREATE OR REPLACE statements mirror the SQL
-- generated by fred_pipeline.gold; ship them for engineers who prefer to build
-- Gold from pure SQL / a SQL Warehouse instead of the Python job.

USE CATALOG {{catalog}};

-- Full vintage history (point-in-time / ALFRED-style).
CREATE OR REPLACE TABLE gold.fred_point_in_time AS
SELECT
    series_id,
    observation_date,
    realtime_start,
    realtime_end,
    value,
    revision_number,
    is_missing,
    ingested_at
FROM silver.fred_observation;

-- One row per (series, date) at its latest revision ("as revised today").
CREATE OR REPLACE TABLE gold.fred_latest_observation AS
WITH ranked AS (
    SELECT
        *,
        ROW_NUMBER() OVER (
            PARTITION BY series_id, observation_date
            ORDER BY realtime_start DESC
        ) AS rn
    FROM silver.fred_observation
)
SELECT
    series_id,
    observation_date,
    value,
    realtime_start,
    realtime_end,
    is_missing,
    revision_number,
    ingested_at
FROM ranked
WHERE rn = 1;

-- Daily, forward-filled feature matrix for optimizer / ML inputs.
CREATE OR REPLACE TABLE gold.fred_macro_feature_daily AS
WITH bounds AS (
    SELECT MIN(observation_date) AS min_d, MAX(observation_date) AS max_d
    FROM gold.fred_latest_observation
),
calendar AS (
    SELECT explode(sequence(
        (SELECT min_d FROM bounds),
        (SELECT max_d FROM bounds),
        INTERVAL 1 DAY
    )) AS as_of_date
),
series_list AS (
    SELECT DISTINCT series_id FROM gold.fred_latest_observation
),
grid AS (
    SELECT c.as_of_date, s.series_id
    FROM calendar c CROSS JOIN series_list s
),
joined AS (
    SELECT
        g.as_of_date,
        g.series_id,
        l.value,
        last_value(l.value, true) OVER (
            PARTITION BY g.series_id ORDER BY g.as_of_date
            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
        ) AS value_ffill
    FROM grid g
    LEFT JOIN gold.fred_latest_observation l
      ON g.series_id = l.series_id AND g.as_of_date = l.observation_date
)
SELECT as_of_date, series_id, value AS raw_value, value_ffill AS value
FROM joined;

-- Quant transforms: MoM / first diff / YoY / expanding (point-in-time safe)
-- z-score per series. The mean_v/std_v window frame is bounded to
-- UNBOUNDED PRECEDING..CURRENT ROW so each row only reflects observations
-- at-or-before its own date -- a whole-partition aggregate would leak future
-- values into every historical row.
CREATE OR REPLACE TABLE gold.fred_feature_transforms AS
WITH base AS (
    SELECT series_id, observation_date, value
    FROM gold.fred_latest_observation WHERE is_missing = false
),
w AS (
    SELECT series_id, observation_date, value,
        LAG(value) OVER (PARTITION BY series_id ORDER BY observation_date) AS prev_value,
        AVG(value) OVER (
            PARTITION BY series_id ORDER BY observation_date
            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
        ) AS mean_v,
        STDDEV_POP(value) OVER (
            PARTITION BY series_id ORDER BY observation_date
            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
        ) AS std_v
    FROM base
),
ya AS (
    SELECT a.*, b.value AS year_ago
    FROM w a
    LEFT JOIN base b
      ON b.series_id = a.series_id
     AND b.observation_date = add_months(a.observation_date, -12)
)
SELECT series_id, observation_date, value,
    CASE WHEN prev_value IS NOT NULL AND prev_value <> 0
         THEN (value - prev_value) / prev_value END AS mom,
    CASE WHEN prev_value IS NOT NULL THEN value - prev_value END AS diff,
    CASE WHEN year_ago IS NOT NULL AND year_ago <> 0
         THEN (value - year_ago) / year_ago END AS yoy,
    CASE WHEN std_v IS NOT NULL AND std_v <> 0
         THEN (value - mean_v) / std_v END AS zscore
FROM ya;

-- Cross-series spreads/ratios. The Python job (fred_pipeline.gold /
-- spread_config.load_spread_defs) reads these from config/spreads.yml so a
-- reviewer can add pairs without touching SQL or Python; this VALUES list
-- must be kept in sync by hand for engineers running pure SQL / a SQL
-- Warehouse, since a static .sql file can't read that YAML at DDL time.
-- op: 'spread' (long-short) or 'ratio' (long/short, guarded against long/0).
CREATE OR REPLACE TABLE gold.fred_curve_spread AS
SELECT s.spread_name, a.observation_date, s.long_leg, s.short_leg,
       CASE WHEN s.op = 'ratio' THEN a.value / b.value
            ELSE a.value - b.value END AS value
FROM (VALUES
        ('T10Y2Y',  'DGS10', 'DGS2',   'spread'),
        ('T10Y3M',  'DGS10', 'DGS3MO', 'spread'),
        ('T2Y3M',   'DGS2',  'DGS3MO', 'spread'),
        ('T30Y10Y', 'DGS30', 'DGS10',  'spread')
     ) AS s(spread_name, long_leg, short_leg, op)
JOIN gold.fred_latest_observation a ON a.series_id = s.long_leg  AND a.is_missing = false
JOIN gold.fred_latest_observation b ON b.series_id = s.short_leg AND b.is_missing = false
                                   AND b.observation_date = a.observation_date
                                   AND (s.op <> 'ratio' OR b.value <> 0);

-- Frequency-aware, N-leg cross-series features (config/cross_series.yml). Unlike
-- fred_curve_spread (same-frequency, 2-leg, above), these align each leg as-of to
-- a target frequency and support composites, so they are computed by the shared
-- Python engine (fred_pipeline.features.compute_cross_series_features) and written
-- by fred_pipeline.gold._build_cross_series — both backends reuse that one
-- function. This DDL just provisions the table shape; the build overwrites it.
CREATE TABLE IF NOT EXISTS gold.fred_cross_series_feature (
    feature_name     STRING,
    op               STRING,
    observation_date DATE,
    value            DOUBLE
)
USING DELTA;

-- Point-in-time (realtime_start-aligned) variant of the cross-series features:
-- each leg uses the value that was actually known (as-first-reported) rather than
-- latest-revised, so the feature series is leak-free for backtests. Reads Silver
-- (all vintages). Computed by the shared Python engine
-- (fred_pipeline.features.compute_cross_series_features_pit) and written by
-- fred_pipeline.gold._build_cross_series_pit. DDL provisions the shape only.
CREATE TABLE IF NOT EXISTS gold.fred_cross_series_feature_pit (
    feature_name     STRING,
    op               STRING,
    observation_date DATE,
    value            DOUBLE,
    basis            STRING
)
USING DELTA;

-- Cross-source reconciliation (config/reconciliations.yml): same-concept series
-- from different sources, aligned and compared with a divergence flag. Computed
-- by the shared Python engine (fred_pipeline.features.compute_source_reconciliation)
-- and written by fred_pipeline.gold._build_source_reconciliation. This DDL just
-- provisions the shape; the build overwrites it.
CREATE TABLE IF NOT EXISTS gold.fred_source_reconciliation (
    name             STRING,
    observation_date DATE,
    series_a         STRING,
    value_a          DOUBLE,
    series_b         STRING,
    value_b          DOUBLE,
    abs_diff         DOUBLE,
    pct_diff         DOUBLE,
    diverged         BOOLEAN
)
USING DELTA;

-- SEC company financials: canonical line items standardized from raw XBRL tags
-- (config/sec_concepts.yml) and derived ratios (config/sec_ratios.yml). Computed
-- by the shared Python engine (fred_pipeline.sec_standardization) and written by
-- fred_pipeline.gold._build_company_financials — the standardization (priority
-- tag coalescing) is impractical in SQL. DDL provisions the shape only.
CREATE TABLE IF NOT EXISTS gold.fred_company_fundamentals (
    cik              STRING,
    concept          STRING,
    statement        STRING,
    observation_date DATE,
    value            DOUBLE
)
USING DELTA;

CREATE TABLE IF NOT EXISTS gold.fred_company_ratios (
    cik              STRING,
    ratio_name       STRING,
    observation_date DATE,
    value            DOUBLE
)
USING DELTA;

-- Revision magnitude: how much each observation moved between its first
-- print and today. Reads raw Silver (every vintage), not gold.fred_latest_
-- observation, since it exists to measure revision behavior itself.
-- Non-vintage series (blank realtime_start) always have revision_count = 1.
CREATE OR REPLACE TABLE gold.fred_revision_stats AS
WITH base AS (
    SELECT series_id, observation_date, realtime_start, value, revision_number
    FROM silver.fred_observation
    WHERE is_missing = false AND value IS NOT NULL
),
bounds AS (
    SELECT series_id, observation_date,
        MIN(revision_number) AS min_rev, MAX(revision_number) AS max_rev,
        COUNT(*) AS revision_count
    FROM base
    GROUP BY series_id, observation_date
)
SELECT b.series_id, b.observation_date, b.revision_count,
    f.value AS first_value, f.realtime_start AS first_realtime_start,
    l.value AS latest_value, l.realtime_start AS latest_realtime_start,
    l.value - f.value AS revision_delta,
    CASE WHEN f.value <> 0 THEN (l.value - f.value) / f.value END AS revision_pct
FROM bounds b
JOIN base f ON f.series_id = b.series_id AND f.observation_date = b.observation_date
          AND f.revision_number = b.min_rev
JOIN base l ON l.series_id = b.series_id AND l.observation_date = b.observation_date
          AND l.revision_number = b.max_rev;

-- ============================================================================
-- Market-terminal analytical views (docs/market_terminal_gold_views.md):
-- star-schema dimensions + the ECON macro dashboard + the Treasury Curve Lab,
-- shaped for Power BI. All computed by the shared Python engines in
-- fred_pipeline.terminal_views and written by
-- fred_pipeline.gold._build_terminal_views — this DDL just provisions the
-- shapes; the build overwrites them.
-- ============================================================================

-- Star-schema hub: presentation semantics (config/series_catalog.yml) merged
-- with title/frequency/units from meta.fred_series. polarity: +1 a rise is
-- bullish, -1 bearish, 0 neutral. default_transform: pc1|pch|chg|bps|level.
CREATE TABLE IF NOT EXISTS gold.dim_series (
    series_id         STRING,
    title             STRING,
    source            STRING,
    frequency         STRING,
    units             STRING,
    econ_category     STRING,
    polarity          INT,
    default_transform STRING,
    scale             STRING,
    decimals          INT,
    notes             STRING
)
USING DELTA;

-- Calendar dimension over the observed date range. is_recession is the NBER
-- USREC flag (NULL until manifests/macro_flags.yml is activated — unknown,
-- never false). fiscal_year is US federal (October start).
CREATE TABLE IF NOT EXISTS gold.dim_date (
    date         DATE,
    year         INT,
    quarter      INT,
    month        INT,
    month_name   STRING,
    is_month_end BOOLEAN,
    fiscal_year  INT,
    is_recession BOOLEAN
)
USING DELTA;

-- ECON macro dashboard: one row per cataloged series at its latest
-- observation — latest/prior/change/YoY, expanding (PIT-safe) z-score and
-- percentile, the no-consensus surprise proxy (latest − trailing-window mean),
-- polarity-adjusted direction, sparkline bounds, staleness, provenance.
CREATE TABLE IF NOT EXISTS gold.macro_indicator_dashboard (
    series_id         STRING,
    econ_category     STRING,
    polarity          INT,
    default_transform STRING,
    as_of_date        DATE,
    latest_date       DATE,
    latest_value      DOUBLE,
    prior_date        DATE,
    prior_value       DOUBLE,
    change_abs        DOUBLE,
    change_pct        DOUBLE,
    yoy_pct           DOUBLE,
    zscore            DOUBLE,
    percentile        DOUBLE,
    surprise          DOUBLE,
    surprise_z        DOUBLE,
    direction_is_good BOOLEAN,
    spark_min         DOUBLE,
    spark_max         DOUBLE,
    staleness_days    INT,
    realtime_start    STRING
)
USING DELTA;

-- Last 36 observations per cataloged series (point_index 0 = oldest), for
-- Power BI sparkline visuals keyed on series_id.
CREATE TABLE IF NOT EXISTS gold.macro_indicator_sparkline (
    series_id        STRING,
    point_index      INT,
    observation_date DATE,
    value            DOUBLE
)
USING DELTA;

-- Per-EconCategory breadth (% of directional series improving,
-- polarity-adjusted) and the surprise index (mean surprise_z).
CREATE TABLE IF NOT EXISTS gold.macro_category_summary (
    econ_category   STRING,
    as_of_date      DATE,
    n_series        INT,
    n_improving     INT,
    n_deteriorating INT,
    breadth_pct     DOUBLE,
    avg_zscore      DOUBLE,
    surprise_index  DOUBLE
)
USING DELTA;

-- Curve Lab, tidy: one row per as-of date × tenor with data
-- (config/curve.yml maps tenors to DGS* series).
CREATE TABLE IF NOT EXISTS gold.treasury_curve (
    as_of_date   DATE,
    tenor_label  STRING,
    tenor_months INT,
    series_id    STRING,
    yield_pct    DOUBLE
)
USING DELTA;

-- Curve Lab, per-date metrics: level (mean of available tenors), 2s10s/3m10s
-- slopes, 2-5-10 curvature, 2-10-30 butterfly, inversion flags, NBER
-- recession flag, and the bull/bear × steepener/flattener move vs the prior
-- curve date (parallel-*/twist-* when only one of level/slope moved).
CREATE TABLE IF NOT EXISTS gold.treasury_curve_metrics (
    as_of_date        DATE,
    level             DOUBLE,
    slope_10y2y       DOUBLE,
    slope_10y3m       DOUBLE,
    curvature_2_5_10  DOUBLE,
    butterfly_2_10_30 DOUBLE,
    is_inverted_10y2y BOOLEAN,
    is_inverted_10y3m BOOLEAN,
    is_recession      BOOLEAN,
    curve_move        STRING
)
USING DELTA;

-- The configured spreads/ratios (config/spreads.yml) enriched with expanding
-- (PIT-safe) z-score/percentile, inversion flag + consecutive-inverted-
-- observation run (spreads only; a ratio has no zero line), bps value, and
-- the NBER recession flag.
CREATE TABLE IF NOT EXISTS gold.curve_spread_daily (
    spread_name      STRING,
    observation_date DATE,
    long_leg         STRING,
    short_leg        STRING,
    value            DOUBLE,
    value_bps        DOUBLE,
    zscore           DOUBLE,
    percentile       DOUBLE,
    is_inverted      BOOLEAN,
    inversion_run    INT,
    is_recession     BOOLEAN
)
USING DELTA;

-- Unique inversion episodes per configured spread (op: spread only): an
-- episode opens on the first negative observation and closes on the first
-- later non-negative one (end_date = that re-steepening date; a single
-- positive print between two inversions splits them into two episodes).
-- Ongoing episodes have end_date NULL and duration measured to
-- last_inverted_date. recession_overlap: any inverted date fell in an NBER
-- recession (NULL until USREC is ingested). Computed by
-- fred_pipeline.terminal_views.compute_spread_inversion_episodes and written
-- by fred_pipeline.gold._build_terminal_views; DDL provisions the shape only.
CREATE TABLE IF NOT EXISTS gold.spread_inversion_episode (
    spread_name        STRING,
    long_leg           STRING,
    short_leg          STRING,
    episode_number     INT,
    start_date         DATE,
    end_date           DATE,
    last_inverted_date DATE,
    observation_count  INT,
    calendar_days      INT,
    trough_value       DOUBLE,
    trough_bps         DOUBLE,
    trough_date        DATE,
    is_ongoing         BOOLEAN,
    recession_overlap  BOOLEAN
)
USING DELTA;

-- ============================================================================
-- Phase 4 rates complex (docs/market_terminal_gold_views.md §4.5–4.7):
-- BMRK benchmark board, FUND funding tape + stress gauge, CRDT credit
-- spreads. Computed by fred_pipeline.terminal_views (configs:
-- config/benchmark_rates.yml / funding.yml / credit.yml) and written by
-- fred_pipeline.gold._build_terminal_views; DDL provisions shapes only.
-- ============================================================================

-- One row per configured rate at its latest observation: change in bps,
-- trend verdict (latest vs. trend_window obs ago, ±1bp dead-band), expanding
-- z-score/percentile, spread to the configured benchmark, and a regime tag
-- (rising→tightening, falling→easing, flat→stable).
CREATE TABLE IF NOT EXISTS gold.benchmark_rate_board (
    series_id               STRING,
    rate_label              STRING,
    rate_category           STRING,
    benchmark_series        STRING,
    as_of_date              DATE,
    latest_date             DATE,
    latest_value            DOUBLE,
    prior_value             DOUBLE,
    change_bps              DOUBLE,
    trend                   STRING,
    spread_to_benchmark_bps DOUBLE,
    zscore                  DOUBLE,
    percentile              DOUBLE,
    regime                  STRING,
    staleness_days          INT
)
USING DELTA;

-- The funding tape: corridor rates, balance-sheet lines, and funding spreads
-- (metric_type rate|balance|spread), each with expanding (PIT-safe)
-- z-score/percentile.
CREATE TABLE IF NOT EXISTS gold.funding_tape_daily (
    metric_name      STRING,
    metric_type      STRING,
    observation_date DATE,
    value            DOUBLE,
    zscore           DOUBLE,
    percentile       DOUBLE
)
USING DELTA;

-- The 0–100 funding stress gauge: weighted mean of the component spreads'
-- expanding z-scores (config/funding.yml stress.components), mapped
-- stress_score = clamp(50 + 20 × composite_z, 0, 100) and bucketed
-- calm (<40) / normal (<60) / elevated (<80) / stressed (≥80). Emitted only
-- on dates where every component spread has a value.
CREATE TABLE IF NOT EXISTS gold.funding_stress_daily (
    observation_date DATE,
    composite_z      DOUBLE,
    stress_score     DOUBLE,
    stress_bucket    STRING,
    n_components     INT
)
USING DELTA;

-- ICE BofA OAS history per configured instrument (percent + bps), change vs.
-- prior print, expanding z-score/percentile, stress-episode flag (expanding
-- percentile ≥ stress_percentile), and the NBER recession overlay (NULL
-- until USREC is ingested).
CREATE TABLE IF NOT EXISTS gold.credit_spread_daily (
    instrument        STRING,
    series_id         STRING,
    category          STRING,
    observation_date  DATE,
    oas_pct           DOUBLE,
    oas_bps           DOUBLE,
    change_bps        DOUBLE,
    zscore            DOUBLE,
    percentile        DOUBLE,
    is_stress_episode BOOLEAN,
    is_recession      BOOLEAN
)
USING DELTA;

-- ============================================================================
-- Phase 2 Inflation Explorer (docs/market_terminal_gold_views.md §4.2):
-- the CPI/PCE item trees from config/inflation_items.yml. Computed by
-- fred_pipeline.terminal_views.compute_inflation_explorer and written by
-- fred_pipeline.gold._build_terminal_views; DDL provisions shapes only.
-- ============================================================================

-- One row per item × month: index level, MoM/YoY (fractions), ΔMoM/ΔYoY
-- acceleration, trailing-3-month annualized rate, the item's relative-
-- importance weight (percent of the headline basket), and weight × MoM
-- contribution in headline percentage points. Month arithmetic is
-- calendar-based, so publication gaps yield NULLs, never wrong-month math.
CREATE TABLE IF NOT EXISTS gold.inflation_explorer (
    series_id              STRING,
    item_label             STRING,
    parent_item            STRING,
    hierarchy_level        INT,
    basket                 STRING,
    sa_nsa                 STRING,
    observation_date       DATE,
    index_value            DOUBLE,
    mom_pct                DOUBLE,
    yoy_pct                DOUBLE,
    mom_accel              DOUBLE,
    yoy_accel              DOUBLE,
    three_month_annualized DOUBLE,
    weight                 DOUBLE,
    contribution_pp        DOUBLE
)
USING DELTA;

-- The contribution waterfall: per tree (basket × sa_nsa) and month where the
-- headline printed, one row per waterfall item ranked by contribution
-- (rank 1 = largest), plus an is_headline_total row carrying the headline's
-- own MoM in percentage points — the bar the item contributions stack
-- against in Power BI's waterfall visual.
CREATE TABLE IF NOT EXISTS gold.inflation_contribution (
    observation_date  DATE,
    basket            STRING,
    sa_nsa            STRING,
    series_id         STRING,
    item_label        STRING,
    contribution_pp   DOUBLE,
    rank_in_month     INT,
    is_headline_total BOOLEAN
)
USING DELTA;

-- ============================================================================
-- Rolling-window stats companions to the daily spread / credit / curve
-- tables. One row per entity × date × window, windows = 1/5/10/21/63/126/252
-- trailing OBSERVATIONS (~trading-day horizons: day, week, 2 weeks, month,
-- quarter, half-year, year). A row appears only once its window is fully
-- populated — no partial-window stats. change = v_t − v_{t−w} in the parent
-- table's native units; pct_change is vs. v_{t−w} (NULL at a zero base;
-- of limited meaning for spreads that cross zero); zscore is against the
-- trailing-w rolling mean/std including the current value (NULL when the
-- window std is 0 — always for window 1). Trailing-only → point-in-time
-- safe. Computed by fred_pipeline.terminal_views.compute_*_rolling and
-- written by fred_pipeline.gold._build_terminal_views; DDL shapes only.
-- ============================================================================

CREATE TABLE IF NOT EXISTS gold.curve_spread_rolling (
    spread_name      STRING,
    observation_date DATE,
    window           INT,
    value            DOUBLE,
    change           DOUBLE,
    pct_change       DOUBLE,
    zscore           DOUBLE
)
USING DELTA;

-- Credit convention: stats over the OAS in bps.
CREATE TABLE IF NOT EXISTS gold.credit_spread_rolling (
    instrument       STRING,
    series_id        STRING,
    observation_date DATE,
    window           INT,
    oas_bps          DOUBLE,
    change_bps       DOUBLE,
    pct_change       DOUBLE,
    zscore           DOUBLE
)
USING DELTA;

-- Yields in percent; change is a percent-point move (×100 for bps).
CREATE TABLE IF NOT EXISTS gold.treasury_curve_rolling (
    tenor_label      STRING,
    tenor_months     INT,
    series_id        STRING,
    observation_date DATE,
    window           INT,
    yield_pct        DOUBLE,
    change           DOUBLE,
    pct_change       DOUBLE,
    zscore           DOUBLE
)
USING DELTA;

-- ============================================================================
-- Phase 5 regime playbook + statistical lab (docs/market_terminal_gold_views
-- .md §4.8–4.9). Computed by fred_pipeline.regime_stats (configs:
-- config/regime.yml / stats_pairs.yml) and written by
-- fred_pipeline.gold._build_regime_stats; DDL provisions shapes only.
-- ============================================================================

-- One row per emission date (union of pillar-input dates, once every pillar
-- is live): the five pillar scores (weighted, direction-adjusted expanding
-- z-scores of config/regime.yml inputs, carried as-of within
-- max_staleness_days), the composite (composite_weight-signed mean; higher =
-- friendlier macro mix), the named regime (ordered rule table, first match
-- wins, else default), and regime_confidence (smallest z-margin by which the
-- matched rule's conditions clear; NULL for the default regime).
CREATE TABLE IF NOT EXISTS gold.macro_regime_daily (
    observation_date  DATE,
    growth_score      DOUBLE,
    inflation_score   DOUBLE,
    liquidity_score   DOUBLE,
    credit_score      DOUBLE,
    policy_score      DOUBLE,
    composite_score   DOUBLE,
    regime_name       STRING,
    regime_confidence DOUBLE
)
USING DELTA;

-- Pearson correlation per configured pair × window × date over transformed
-- (default first-differenced), date-aligned series. window 0 = expanding
-- full sample to date (from the 3rd common obs); rolling windows emit only
-- once fully populated.
CREATE TABLE IF NOT EXISTS gold.series_correlation (
    series_a         STRING,
    series_b         STRING,
    transform_a      STRING,
    transform_b      STRING,
    window           INT,
    observation_date DATE,
    correlation      DOUBLE,
    n_obs            INT
)
USING DELTA;

-- Cross-correlation at lags -max_lag..+max_lag per configured pair
-- (positive lag = series_a LEADS series_b), with the pair's best_lag
-- (largest |CCF|) and both Granger F-test directions (granger_*_ab = does a
-- help predict b?) denormalized onto every row. p-values are exact
-- F-distribution tails (pure-Python incomplete beta, no SciPy).
CREATE TABLE IF NOT EXISTS gold.series_lead_lag (
    series_a          STRING,
    series_b          STRING,
    transform_a       STRING,
    transform_b       STRING,
    lag               INT,
    cross_correlation DOUBLE,
    n_obs             INT,
    best_lag          INT,
    granger_f_ab      DOUBLE,
    granger_p_ab      DOUBLE,
    granger_f_ba      DOUBLE,
    granger_p_ba      DOUBLE,
    as_of_date        DATE
)
USING DELTA;

-- ============================================================================
-- Phase 6 global tables + Power BI catalog (docs/market_terminal_gold_views
-- .md §4.9 global modules). Computed by fred_pipeline.global_views (config:
-- config/global_series.yml) and written by
-- fred_pipeline.gold._build_global_views; DDL provisions shapes only.
-- ============================================================================

-- CPI YoY by country (GCPI): one row per country x print — the YoY rate in
-- percent, change vs the prior print, a trend verdict (accelerating/cooling/
-- flat, ±0.05pp dead-band), the signed consecutive-print streak (+n
-- accelerating / -n cooling; flat resets), and the gap to the central-bank
-- target. World Bank FP.CPI.TOTL.ZG entries are annual; the US runs off
-- monthly CPIAUCSL (yoy_from_index).
CREATE TABLE IF NOT EXISTS gold.global_inflation (
    country          STRING,
    iso3             STRING,
    region           STRING,
    series_id        STRING,
    observation_date DATE,
    cpi_yoy_pct      DOUBLE,
    change_pp        DOUBLE,
    trend            STRING,
    streak           INT,
    target_pct       DOUBLE,
    vs_target_pp     DOUBLE
)
USING DELTA;

-- Policy rates by country (GPOL): one row per country x print — the rate in
-- percent, change vs prior print in bps, the most recent nonzero move
-- (carried), the stance from that move's sign (hiking/cutting; on-hold
-- before any move), and the ex-post real rate (policy − the country's
-- latest CPI YoY print on-or-before the date, when configured and fresh).
CREATE TABLE IF NOT EXISTS gold.global_policy_rates (
    country          STRING,
    iso3             STRING,
    region           STRING,
    series_id        STRING,
    observation_date DATE,
    policy_rate_pct  DOUBLE,
    change_bps       DOUBLE,
    last_move_bps    DOUBLE,
    stance           STRING,
    real_rate_pct    DOUBLE
)
USING DELTA;

-- The report author's manifest of Gold objects: name, type, terminal module,
-- grain, intended Power BI visual, description. Single source of truth is
-- fred_pipeline.global_views.POWERBI_CATALOG (a table, not the view the plan
-- sketched, so the row list isn't hand-duplicated across SQL dialects).
CREATE TABLE IF NOT EXISTS gold.powerbi_catalog (
    object_name     STRING,
    object_type     STRING,
    module          STRING,
    grain           STRING,
    intended_visual STRING,
    description     STRING
)
USING DELTA;

-- ============================================================================
-- Equity slice (handoff.md "Equity Price & Total Return — Two-Source
-- Sub-Plan"): Stooq price return + ETF constituents. Computed by
-- fred_pipeline.equity_views from the scalar-explode Silver series
-- (<ticker>:close, <ETF>:<constituent>) and written by
-- fred_pipeline.gold._build_equity_views; DDL provisions shapes only. The
-- Tiingo total-return table (equity_total_return_index) is the next slice.
-- ============================================================================

-- Daily price return per ticker from the split-adjusted Stooq close: the
-- close, day-over-day change and simple return, and a cumulative
-- price-return index (=100 at each ticker's first observation). Dividends
-- excluded (that's the Tiingo total-return slice).
CREATE TABLE IF NOT EXISTS gold.equity_return_daily (
    ticker             STRING,
    observation_date   DATE,
    close              DOUBLE,
    price_change       DOUBLE,
    price_return       DOUBLE,
    price_return_index DOUBLE
)
USING DELTA;

-- ETF constituents exploded from the daily holdings file: one row per
-- ETF x constituent x snapshot date, the weight (percent), the within-
-- snapshot weight rank, and is_latest_snapshot on the most recent as-of date
-- per ETF (filter to that for "current membership"). Snapshot history
-- accumulates through the normal incremental path.
CREATE TABLE IF NOT EXISTS gold.index_constituents (
    index_etf          STRING,
    constituent        STRING,
    observation_date   DATE,
    weight_pct         DOUBLE,
    weight_rank        INT,
    is_latest_snapshot BOOLEAN
)
USING DELTA;

-- Equity total return (source: tiingo; scalar-explode <ticker>:close/divCash/
-- splitFactor). One row per ticker x date: raw close, dividend, split factor;
-- daily price and total return (split-adjusted, dividends reinvested);
-- cumulative price- and total-return indices (=100 at each ticker's first
-- date; their gap is reinvested income); trailing-12m dividend and yield.
-- Derived from RAW inputs (not Tiingo adjClose) so it survives dividend
-- restatements. Written by fred_pipeline.gold._build_equity_views.
CREATE TABLE IF NOT EXISTS gold.equity_total_return_index (
    ticker                STRING,
    observation_date      DATE,
    close                 DOUBLE,
    dividend              DOUBLE,
    split_factor          DOUBLE,
    price_return          DOUBLE,
    total_return          DOUBLE,
    price_return_index    DOUBLE,
    total_return_index    DOUBLE,
    trailing_12m_dividend DOUBLE,
    dividend_yield_pct    DOUBLE
)
USING DELTA;
